(function(w){"use strict";const ID="sphere-volume";function compute(x){const r=Number(x.radius);if(!Number.isFinite(r)||r<0)return{error:"0 이상의 반지름을 입력해 주세요."};return{value:4*Math.PI*r*r*r/3};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>반지름</label><input class="hm-calc-input" inputmode="decimal" data-key="radius" placeholder="" value=""></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("구의 부피",api.formatNumber(r.value,10),"V = 4πr³ ÷ 3"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
